/**
 * SMS channel handler — sends SMS notifications in response to events.
 *
 * Follows the same dual-pattern as NotificationService:
 * - EventBus subscription for order:created events
 * - CallbackRegistry for order:status-changed events
 *
 * Depends on:
 * - EventBus (event system) for receiving order:created events
 * - CallbackRegistry (direct callbacks) for order:status-changed events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface SmsMessage {
  id: string;
  phoneNumber: string;
  message: string;
  sentAt: Date;
}

let nextId = 1;

function generateSmsId(): string {
  return `sms-${String(nextId++).padStart(4, '0')}`;
}

export function resetSmsIdCounter(): void {
  nextId = 1;
}

export class SmsChannelService {
  private logger = new Logger('SmsChannelService');
  private messages: SmsMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for SMS triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send SMS confirmation.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending SMS for order ${event.order.id}`);

    const itemCount = event.order.items.reduce((sum, item) => sum + item.quantity, 0);

    this.sendSms({
      phoneNumber: event.user.id,
      message: `Order ${event.order.id} confirmed: ${itemCount} item(s), total $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — send SMS status update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending SMS status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendSms({
      phoneNumber: event.order.userId,
      message: `Order ${event.order.id}: status changed to ${event.newStatus}`,
    });
  }

  /**
   * Send an SMS (in-memory for this demo).
   */
  private sendSms(params: { phoneNumber: string; message: string }): void {
    const sms: SmsMessage = {
      id: generateSmsId(),
      phoneNumber: params.phoneNumber,
      message: params.message,
      sentAt: new Date(),
    };
    this.messages.push(sms);
    this.logger.info(`SMS sent: ${sms.id} to ${params.phoneNumber}`);
  }

  /**
   * Get all sent SMS messages.
   */
  getMessages(): SmsMessage[] {
    return [...this.messages];
  }

  /**
   * Get SMS messages for a specific phone number.
   */
  getMessagesForNumber(phoneNumber: string): SmsMessage[] {
    return this.messages.filter((m) => m.phoneNumber === phoneNumber);
  }

  /**
   * Get the count of sent SMS messages.
   */
  getMessageCount(): number {
    return this.messages.length;
  }

  /**
   * Clear all messages (useful for testing).
   */
  clearMessages(): void {
    this.messages = [];
  }
}

/**
 * Webhook channel handler — delivers event payloads to registered webhook URLs.
 *
 * Follows the same dual-pattern as NotificationService:
 * - EventBus subscription for order:created events
 * - CallbackRegistry for order:status-changed events
 *
 * Depends on:
 * - EventBus (event system) for receiving order:created events
 * - CallbackRegistry (direct callbacks) for order:status-changed events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface WebhookDelivery {
  id: string;
  url: string;
  eventType: string;
  payload: Record<string, unknown>;
  deliveredAt: Date;
}

let nextId = 1;

function generateWebhookId(): string {
  return `wh-${String(nextId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounter(): void {
  nextId = 1;
}

export class WebhookChannelService {
  private logger = new Logger('WebhookChannelService');
  private deliveries: WebhookDelivery[] = [];
  private webhookUrls: string[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a webhook URL to receive event deliveries.
   */
  addWebhookUrl(url: string): void {
    this.webhookUrls.push(url);
  }

  /**
   * Remove a webhook URL.
   */
  removeWebhookUrl(url: string): void {
    const index = this.webhookUrls.indexOf(url);
    if (index >= 0) {
      this.webhookUrls.splice(index, 1);
    }
  }

  /**
   * Get registered webhook URLs.
   */
  getWebhookUrls(): string[] {
    return [...this.webhookUrls];
  }

  /**
   * Register event handlers for webhook triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — deliver webhook payload.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Delivering webhook for order:created ${event.order.id}`);

    const payload: Record<string, unknown> = {
      event: 'order:created',
      orderId: event.order.id,
      userId: event.user.id,
      total: event.order.total,
      itemCount: event.order.items.length,
      timestamp: event.timestamp,
    };

    for (const url of this.webhookUrls) {
      this.deliverWebhook(url, 'order:created', payload);
    }
  }

  /**
   * Handle order status change — deliver webhook payload.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Delivering webhook for order:status-changed ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const payload: Record<string, unknown> = {
      event: 'order:status-changed',
      orderId: event.order.id,
      previousStatus: event.previousStatus,
      newStatus: event.newStatus,
      timestamp: event.timestamp,
    };

    for (const url of this.webhookUrls) {
      this.deliverWebhook(url, 'order:status-changed', payload);
    }
  }

  /**
   * Deliver a webhook payload (in-memory for this demo).
   */
  private deliverWebhook(
    url: string,
    eventType: string,
    payload: Record<string, unknown>,
  ): void {
    const delivery: WebhookDelivery = {
      id: generateWebhookId(),
      url,
      eventType,
      payload,
      deliveredAt: new Date(),
    };
    this.deliveries.push(delivery);
    this.logger.info(`Webhook delivered: ${delivery.id} to ${url}`);
  }

  /**
   * Get all webhook deliveries.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific URL.
   */
  getDeliveriesForUrl(url: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.url === url);
  }

  /**
   * Get the count of webhook deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all deliveries (useful for testing).
   */
  clearDeliveries(): void {
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  SmsChannelService,
  resetSmsIdCounter,
} from '../../src/services/sms-channel.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('SmsChannelService', () => {
  let eventBus: EventBus;
  let service: SmsChannelService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    service = new SmsChannelService(eventBus);
    resetSmsIdCounter();
  });

  describe('order:created handler', () => {
    it('should send SMS on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const messages = service.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.phoneNumber).toBe('user-1');
      expect(messages[0]?.message).toContain('order-1');
      expect(messages[0]?.message).toContain('2 item(s)');
      expect(messages[0]?.message).toContain('$20.00');
    });

    it('should count total items across all order items', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 3, unitPrice: 5 },
          ],
          total: 35,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const messages = service.getMessages();
      expect(messages[0]?.message).toContain('5 item(s)');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send SMS on status change', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const messages = service.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.phoneNumber).toBe('user-1');
      expect(messages[0]?.message).toContain('order-1');
      expect(messages[0]?.message).toContain('confirmed');
    });
  });

  describe('message management', () => {
    it('should count messages', () => {
      expect(service.getMessageCount()).toBe(0);

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getMessageCount()).toBe(1);
    });

    it('should filter by phone number', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getMessagesForNumber('user-1')).toHaveLength(1);
      expect(service.getMessagesForNumber('user-2')).toHaveLength(0);
    });

    it('should clear messages', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearMessages();
      expect(service.getMessageCount()).toBe(0);
    });

    it('should generate sequential SMS IDs', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const messages = service.getMessages();
      expect(messages[0]?.id).toBe('sms-0001');
      expect(messages[1]?.id).toBe('sms-0002');
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookChannelService,
  resetWebhookIdCounter,
} from '../../src/services/webhook-channel.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookChannelService', () => {
  let eventBus: EventBus;
  let service: WebhookChannelService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    service = new WebhookChannelService(eventBus);
    resetWebhookIdCounter();
  });

  describe('webhook URL management', () => {
    it('should add and list webhook URLs', () => {
      service.addWebhookUrl('https://example.com/hook1');
      service.addWebhookUrl('https://example.com/hook2');

      expect(service.getWebhookUrls()).toEqual([
        'https://example.com/hook1',
        'https://example.com/hook2',
      ]);
    });

    it('should remove a webhook URL', () => {
      service.addWebhookUrl('https://example.com/hook1');
      service.addWebhookUrl('https://example.com/hook2');
      service.removeWebhookUrl('https://example.com/hook1');

      expect(service.getWebhookUrls()).toEqual(['https://example.com/hook2']);
    });
  });

  describe('order:created handler', () => {
    it('should deliver webhook on order created', async () => {
      service.addWebhookUrl('https://example.com/hook');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const deliveries = service.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
      expect(deliveries[0]?.eventType).toBe('order:created');
      expect(deliveries[0]?.payload.orderId).toBe('order-1');
      expect(deliveries[0]?.payload.total).toBe(20);
    });

    it('should deliver to multiple webhook URLs', async () => {
      service.addWebhookUrl('https://example.com/hook1');
      service.addWebhookUrl('https://example.com/hook2');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getDeliveryCount()).toBe(2);
      expect(service.getDeliveriesForUrl('https://example.com/hook1')).toHaveLength(1);
      expect(service.getDeliveriesForUrl('https://example.com/hook2')).toHaveLength(1);
    });

    it('should not deliver if no webhook URLs registered', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getDeliveryCount()).toBe(0);
    });
  });

  describe('order:status-changed handler', () => {
    it('should deliver webhook on status change', () => {
      service.addWebhookUrl('https://example.com/hook');

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const deliveries = service.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.eventType).toBe('order:status-changed');
      expect(deliveries[0]?.payload.orderId).toBe('order-1');
      expect(deliveries[0]?.payload.previousStatus).toBe('pending');
      expect(deliveries[0]?.payload.newStatus).toBe('confirmed');
    });
  });

  describe('delivery management', () => {
    it('should count deliveries', () => {
      expect(service.getDeliveryCount()).toBe(0);

      service.addWebhookUrl('https://example.com/hook');
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getDeliveryCount()).toBe(1);
    });

    it('should clear deliveries', () => {
      service.addWebhookUrl('https://example.com/hook');
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearDeliveries();
      expect(service.getDeliveryCount()).toBe(0);
    });

    it('should generate sequential webhook IDs', () => {
      service.addWebhookUrl('https://example.com/hook');

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const deliveries = service.getDeliveries();
      expect(deliveries[0]?.id).toBe('wh-0001');
      expect(deliveries[1]?.id).toBe('wh-0002');
    });
  });
});

